function stb(slug) {
  return `https://www.sharktankblog.com/business/${slug}/`;
}

function row({ episode, slug, name, description, deal, investors = [], terms = null, revenueRaw = null, revenueAmount = null, revenueAttributionPercent = null, industry, active = true, businessStatus = active ? "active" : "unknown", confidence = "high" }) {
  const sourceUrl = stb(slug);
  return {
    id: `s17e${episode}-${slug}`,
    sourceType: "supplemental",
    season: 17,
    episode,
    airDate: dates[episode],
    companyName: name,
    description,
    dealStatus: deal,
    dealTermsRaw: terms,
    investors,
    businessStatus,
    revenueRaw,
    revenueAmount,
    revenueAttributionPercent,
    revenueDate: `${dates[episode]} pitch / Season 17 research`,
    sourceUrl,
    sourceUrlsRaw: `${abc[episode]} | ${sourceUrl}`,
    industry,
    enrichmentConfidence: confidence
  };
}

